sys_variable_value.value:
(function execute(inputs, outputs) {
  var userSysId = inputs.current.getValue("opened_by");
  var userAccess = new UserAccess();
  userAccess.setUser(userSysId);
  var isExactlySubscriber = userAccess.isExactlySubscriber();
  if (isExactlySubscriber) {
    gs.eventQueue(Constants.EVENT.requestRejected, inputs.current, userSysId);
  }

})(inputs, outputs);

